import{_ as a,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const l="/assets/shop-manage.CDAmBgqw.png",m=JSON.parse('{"title":"❌ 如何刪除與註銷商店","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Delete-Shop.md","filePath":"Mc-Delete-Shop.md"}'),i={name:"Mc-Delete-Shop.md"};function s(n,e,c,h,_,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="❌-如何刪除與註銷商店" tabindex="-1">❌ 如何刪除與註銷商店 <a class="header-anchor" href="#❌-如何刪除與註銷商店" aria-label="Permalink to &quot;❌ 如何刪除與註銷商店&quot;">​</a></h1><p>當您不再需要某個商店，或是想要更改販售的商品時，可以將其刪除並註銷。</p><hr><h2 id="🗑️-1-方法一-直接敲除告示牌" tabindex="-1">🗑️ 1. 方法一：直接敲除告示牌 <a class="header-anchor" href="#🗑️-1-方法一-直接敲除告示牌" aria-label="Permalink to &quot;🗑️ 1. 方法一：直接敲除告示牌&quot;">​</a></h2><ul><li>最直觀的方法：直接使用工具（如斧頭）或徒手<strong>敲掉商店箱子上的告示牌</strong>。</li><li>告示牌破碎的同時，系統會發送通知確認商店已註銷，並會自動清除箱子上方對應的商品懸浮展示模型。</li></ul><hr><h2 id="🖱️-2-方法二-透過店主控制面板刪除" tabindex="-1">🖱️ 2. 方法二：透過店主控制面板刪除 <a class="header-anchor" href="#🖱️-2-方法二-透過店主控制面板刪除" aria-label="Permalink to &quot;🖱️ 2. 方法二：透過店主控制面板刪除&quot;">​</a></h2><ol><li>店主對著自己商店的 <strong>告示牌點選【右鍵】</strong>。</li><li>聊天欄會開啟店主專屬控制面板。</li><li>點選最後一行的紅字 <strong><code>[刪除商店]</code></strong>。</li></ol><p><img src="'+l+'" alt="店主控制與管理面板"></p><ol start="4"><li>系統會即時移除該商店的註銷狀態，告示牌的文字會自動被清空，方便您重新書寫。</li></ol>',10)])])}const u=a(i,[["render",s]]);export{m as __pageData,u as default};
